async function sendOnline(client, online) {
  await client.call({
    _: "account.updateStatus",
    offline: !online
  });
}
const TIMER_ID = "online";
const TIMER_INTERVAL = 24e4;
async function setOnline(client, online = true) {
  if (online) {
    await client.timers.upsert({
      kind: "rpc",
      key: TIMER_ID,
      interval: TIMER_INTERVAL,
      startNow: true,
      request: {
        _: "account.updateStatus",
        offline: false
      }
    });
  } else {
    await client.timers.cancel(TIMER_ID);
    await client.call({
      _: "account.updateStatus",
      offline: true
    });
  }
}
export {
  sendOnline,
  setOnline
};
